import{_ as a,c as e,o as r,a1 as d}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"进阶功能","description":"学习 Clawdbot 的高级功能配置，包括 AI 模型配置、多 Agent 协作、浏览器自动化、命令执行工具、Web 搜索工具、Canvas 可视化界面、语音唤醒与 TTS、记忆系统、Cron 定时任务、技能平台、安全沙箱和远程 Gateway。","frontmatter":{"title":"进阶功能","sidebarTitle":"解锁 AI 超能力","subtitle":"进阶功能","description":"学习 Clawdbot 的高级功能配置，包括 AI 模型配置、多 Agent 协作、浏览器自动化、命令执行工具、Web 搜索工具、Canvas 可视化界面、语音唤醒与 TTS、记忆系统、Cron 定时任务、技能平台、安全沙箱和远程 Gateway。","prerequisite":["start/getting-started","start/gateway-startup"],"order":185},"headers":[],"relativePath":"zh/moltbot/moltbot/advanced/index.md","filePath":"zh/moltbot/moltbot/advanced/index.md"}'),o={name:"zh/moltbot/moltbot/advanced/index.md"};function l(h,t,i,n,s,b){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="进阶功能" tabindex="-1">进阶功能 <a class="header-anchor" href="#进阶功能" aria-label="Permalink to &quot;进阶功能&quot;">​</a></h1><h2 id="本章概述" tabindex="-1">本章概述 <a class="header-anchor" href="#本章概述" aria-label="Permalink to &quot;本章概述&quot;">​</a></h2><p>本章深入介绍 Clawdbot 的高级功能，帮助你充分利用 AI 助手的强大能力。从 AI 模型配置和多 Agent 协作，到浏览器自动化、记忆系统和语音功能，你可以根据需求选择学习。</p><div class="info custom-block"><p class="custom-block-title">前置条件</p><p>学习本章前，请先完成以下内容：</p><ul><li><a href="./../../start/getting-started/">快速开始</a></li><li><a href="./../../start/gateway-startup/">启动 Gateway</a></li></ul></div><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><p>根据你的需求，可以选择不同的学习路径：</p><h3 id="🚀-快速上手路径-推荐新手" tabindex="-1">🚀 快速上手路径（推荐新手） <a class="header-anchor" href="#🚀-快速上手路径-推荐新手" aria-label="Permalink to &quot;🚀 快速上手路径（推荐新手）&quot;">​</a></h3><ol><li><a href="./models-auth/">AI 模型与认证配置</a> - 配置你喜欢的 AI 模型</li><li><a href="./tools-exec/">命令执行工具与审批</a> - 让 AI 安全地执行命令</li><li><a href="./tools-web/">Web 搜索与抓取工具</a> - 扩展 AI 的知识获取能力</li></ol><h3 id="🤖-ai-能力扩展路径" tabindex="-1">🤖 AI 能力扩展路径 <a class="header-anchor" href="#🤖-ai-能力扩展路径" aria-label="Permalink to &quot;🤖 AI 能力扩展路径&quot;">​</a></h3><ol><li><a href="./session-management/">会话管理与多 Agent</a> - 理解 AI 协作机制</li><li><a href="./memory-system/">记忆系统与向量搜索</a> - 让 AI 记住重要信息</li><li><a href="./skills-platform/">技能平台与 ClawdHub</a> - 使用和分享技能包</li></ol><h3 id="🔧-自动化工具路径" tabindex="-1">🔧 自动化工具路径 <a class="header-anchor" href="#🔧-自动化工具路径" aria-label="Permalink to &quot;🔧 自动化工具路径&quot;">​</a></h3><ol><li><a href="./tools-browser/">浏览器自动化工具</a> - 网页操作自动化</li><li><a href="./cron-automation/">Cron 定时任务与 Webhook</a> - 定时任务与事件触发</li><li><a href="./remote-gateway/">远程 Gateway 与 Tailscale</a> - 远程访问你的 AI 助手</li></ol><h3 id="🎨-交互体验路径" tabindex="-1">🎨 交互体验路径 <a class="header-anchor" href="#🎨-交互体验路径" aria-label="Permalink to &quot;🎨 交互体验路径&quot;">​</a></h3><ol><li><a href="./canvas/">Canvas 可视化界面与 A2UI</a> - 可视化交互界面</li><li><a href="./voice-tts/">语音唤醒与文本转语音</a> - 语音交互功能</li></ol><h3 id="🔒-安全与部署路径" tabindex="-1">🔒 安全与部署路径 <a class="header-anchor" href="#🔒-安全与部署路径" aria-label="Permalink to &quot;🔒 安全与部署路径&quot;">​</a></h3><ol><li><a href="./security-sandbox/">安全与沙箱隔离</a> - 深入了解安全机制</li><li><a href="./remote-gateway/">远程 Gateway 与 Tailscale</a> - 安全的远程访问</li></ol><h2 id="子页面导航" tabindex="-1">子页面导航 <a class="header-anchor" href="#子页面导航" aria-label="Permalink to &quot;子页面导航&quot;">​</a></h2><h3 id="核心配置" tabindex="-1">核心配置 <a class="header-anchor" href="#核心配置" aria-label="Permalink to &quot;核心配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>主题</th><th>描述</th><th>预计时间</th></tr></thead><tbody><tr><td><a href="./models-auth/">AI 模型与认证配置</a></td><td>配置 Anthropic、OpenAI、OpenRouter、Ollama 等多种 AI 模型提供商和认证方式</td><td>15 分钟</td></tr><tr><td><a href="./session-management/">会话管理与多 Agent</a></td><td>学习会话模型、会话隔离、子 Agent 协作、上下文压缩等核心概念</td><td>20 分钟</td></tr></tbody></table><h3 id="工具系统" tabindex="-1">工具系统 <a class="header-anchor" href="#工具系统" aria-label="Permalink to &quot;工具系统&quot;">​</a></h3><table tabindex="0"><thead><tr><th>主题</th><th>描述</th><th>预计时间</th></tr></thead><tbody><tr><td><a href="./tools-browser/">浏览器自动化工具</a></td><td>使用浏览器工具进行网页自动化、截图、操作表单等</td><td>25 分钟</td></tr><tr><td><a href="./tools-exec/">命令执行工具与审批</a></td><td>配置和使用 exec 工具，了解安全审批机制和权限控制</td><td>15 分钟</td></tr><tr><td><a href="./tools-web/">Web 搜索与抓取工具</a></td><td>使用 web_search 和 web_fetch 工具进行网络搜索和内容抓取</td><td>20 分钟</td></tr></tbody></table><h3 id="交互体验" tabindex="-1">交互体验 <a class="header-anchor" href="#交互体验" aria-label="Permalink to &quot;交互体验&quot;">​</a></h3><table tabindex="0"><thead><tr><th>主题</th><th>描述</th><th>预计时间</th></tr></thead><tbody><tr><td><a href="./canvas/">Canvas 可视化界面与 A2UI</a></td><td>了解 Canvas A2UI 推送机制、可视化界面操作和自定义界面</td><td>20 分钟</td></tr><tr><td><a href="./voice-tts/">语音唤醒与文本转语音</a></td><td>配置 Voice Wake、Talk Mode 和 TTS 提供商，实现语音交互</td><td>15 分钟</td></tr></tbody></table><h3 id="智能扩展" tabindex="-1">智能扩展 <a class="header-anchor" href="#智能扩展" aria-label="Permalink to &quot;智能扩展&quot;">​</a></h3><table tabindex="0"><thead><tr><th>主题</th><th>描述</th><th>预计时间</th></tr></thead><tbody><tr><td><a href="./memory-system/">记忆系统与向量搜索</a></td><td>配置和使用记忆系统（SQLite-vec、FTS5、混合搜索）</td><td>25 分钟</td></tr><tr><td><a href="./skills-platform/">技能平台与 ClawdHub</a></td><td>了解技能系统、Bundled/Managed/Workspace 技能、ClawdHub 集成</td><td>20 分钟</td></tr></tbody></table><h3 id="自动化与部署" tabindex="-1">自动化与部署 <a class="header-anchor" href="#自动化与部署" aria-label="Permalink to &quot;自动化与部署&quot;">​</a></h3><table tabindex="0"><thead><tr><th>主题</th><th>描述</th><th>预计时间</th></tr></thead><tbody><tr><td><a href="./cron-automation/">Cron 定时任务与 Webhook</a></td><td>配置定时任务、Webhook 触发、Gmail Pub/Sub 等自动化功能</td><td>20 分钟</td></tr><tr><td><a href="./remote-gateway/">远程 Gateway 与 Tailscale</a></td><td>通过 Tailscale Serve/Funnel 或 SSH 隧道远程访问 Gateway</td><td>15 分钟</td></tr></tbody></table><h3 id="安全机制" tabindex="-1">安全机制 <a class="header-anchor" href="#安全机制" aria-label="Permalink to &quot;安全机制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>主题</th><th>描述</th><th>预计时间</th></tr></thead><tbody><tr><td><a href="./security-sandbox/">安全与沙箱隔离</a></td><td>了解安全模型、工具权限控制、Sandbox 隔离、Docker 化部署</td><td>20 分钟</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章学习后，你可以：</p><ol><li><strong>深入学习</strong> - 查看 <a href="./../../faq/troubleshooting/">故障排除</a> 解决遇到的问题</li><li><strong>了解部署</strong> - 查看 <a href="./../../appendix/deployment/">部署选项</a> 将 Clawdbot 部署到生产环境</li><li><strong>开发扩展</strong> - 查看 <a href="./../../appendix/development/">开发指南</a> 学习如何开发插件和贡献代码</li><li><strong>查看配置</strong> - 参考 <a href="./../../appendix/config-reference/">完整配置参考</a> 了解所有配置选项</li></ol><div class="tip custom-block"><p class="custom-block-title">学习建议</p><p>建议你根据自己的实际需求选择学习路径。如果不确定从哪里开始，可以按照「快速上手路径」逐步学习，其他主题可以在需要时再深入学习。</p></div>',33)])])}const u=a(o,[["render",l]]);export{f as __pageData,u as default};
